import base64,os
D="mipmap-xhdpi"
IC=""
FG=""
B="android/app/src/main/res"
d=os.path.join(B,D)
os.makedirs(d,exist_ok=True)
ic=base64.b64decode(IC)
fg=base64.b64decode(FG)
open(os.path.join(d,"ic_launcher.png"),"wb").write(ic)
open(os.path.join(d,"ic_launcher_round.png"),"wb").write(ic)
open(os.path.join(d,"ic_launcher_foreground.png"),"wb").write(fg)
print("OK mipmap-xhdpi")